import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛王 = (bi) => 菩薩坐身(bi, {
    胸瓔滴z: 30.0,
    臂(bi, 筆) {
        const { 骨, 細, 陰, 陽 } = 筆;
        // 上臂：兩肩垂而肘收（常勢），肘z 40——摺臂之肘
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.0); });
        // 尊左前臂（後，先落）：自畫面右肘斜上貫至胸左，肌腹在上，肘有帽
        骨(() => 陰(() => 前臂(bi, 筆, [13.7, 39.9], [-1.2, 34.6], { 寬根: 2.6, 寬梢: 2.0, 弓: 0.45, 肘帽: true })));
        側拳(bi, -3.3, 33.9, 0.33, 1.25); // 尊左拳（腕側向其肘）
        // 尊右前臂（前，後落）：蔽鑿其疊（右壓左，歸命之序）
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.3], [1.4, 35.0], { 寬根: 2.6, 寬梢: 2.0, 弓: -0.45, 肘帽: true })));
        側拳(bi, 3.5, 34.3, -0.33, 1.25, -1); // 尊右拳（鏡）
        // 嚴：臂釧常位；腕釧順腕之斜
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-1.0, 33.6, -0.5, 34.7, -1.0, 35.9], [-0.1, 33.8, 0.4, 34.9, -0.1, 36.1]], [-0.3, 34.9]);
            腕釧(bi, [[1.2, 34.0, 0.7, 35.1, 1.2, 36.3], [0.3, 34.2, -0.2, 35.3, 0.3, 36.5]], [0.5, 35.3]);
        });
    },
});
